return [{
  service: $json.body?.service || $json.service,
  audience: $json.body?.audience || $json.audience,
  problem: $json.body?.problem || $json.problem,
  pain_intensity: $json.body?.pain_intensity || $json.pain_intensity,
  willingness_to_pay: $json.body?.willingness_to_pay || $json.willingness_to_pay
}];

try {
  const cleaned = $json.output.replace(/```json|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  return match ? JSON.parse(match[0]) : { error: 'Invalid JSON', raw: cleaned };
} catch (e) {
  return { error: 'Parsing failed', raw: $json.output };
}
